-- Script para recrear la tabla con 154 puntos y coordenadas
DROP TABLE IF EXISTS public.charging_points;

CREATE TABLE public.charging_points (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    region TEXT,
    province TEXT,
    city_or_canton TEXT NOT NULL,
    name TEXT NOT NULL,
    speed TEXT,
    charger_type TEXT,
    power TEXT,
    schedule TEXT,
    cost_type TEXT,
    gps_link TEXT,
    lat NUMERIC,
    lng NUMERIC,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
ALTER TABLE public.charging_points ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Permitir lectura pública de puntos de carga" ON public.charging_points FOR SELECT USING (true);
  
BEGIN;
COMMIT;